(function(){const section=document.getElementById('trail-photos');if(!section||typeof GALLERY_DATA==='undefined')return;const trailKey=section.dataset.trail;const cat=GALLERY_DATA[trailKey];if(!cat||!cat.images.length){section.style.display='none';return;}const photos=cat.images;const BATCH=24;let rendered=0;const grid=section.querySelector('.trail-photo-grid');const loadMoreBtn=section.querySelector('.trail-load-more');if(!grid||!loadMoreBtn)return;const countEl=section.querySelector('.trail-photo-count');if(countEl)countEl.textContent=photos.length;const lightbox=document.getElementById('trail-lightbox');const lbImg=document.getElementById('tlb-img');const lbClose=document.getElementById('tlb-close');const lbPrev=document.getElementById('tlb-prev');const lbNext=document.getElementById('tlb-next');const lbCounter=document.getElementById('tlb-counter');const lbSpinner=document.getElementById('tlb-spinner');if(!lightbox||!lbImg||!lbClose||!lbPrev||!lbNext||!lbCounter||!lbSpinner)return;let lbIndex=0;function openLB(i){lbIndex=i;lightbox.classList.add('open');document.body.style.overflow='hidden';loadLB(i);}function closeLB(){lightbox.classList.remove('open');document.body.style.overflow='';lbImg.src='';}function loadLB(i){lbImg.style.opacity='0';lbSpinner.style.display='block';lbCounter.textContent=`${i+1} / ${photos.length}`;const pre=new Image();pre.onload=pre.onerror=()=>{lbImg.src=photos[i];lbImg.style.opacity='1';lbSpinner.style.display='none';};pre.src=photos[i];}function prev(){lbIndex=(lbIndex-1+photos.length)%photos.length;loadLB(lbIndex);}function next(){lbIndex=(lbIndex+1)%photos.length;loadLB(lbIndex);}lbClose.addEventListener('click',closeLB);lbPrev.addEventListener('click',prev);lbNext.addEventListener('click',next);lightbox.addEventListener('click',e=>{if(e.target===lightbox)closeLB();});document.addEventListener('keydown',e=>{if(!lightbox.classList.contains('open'))return;if(e.key==='Escape')closeLB();if(e.key==='ArrowLeft')prev();if(e.key==='ArrowRight')next();});let tx=0;lightbox.addEventListener('touchstart',e=>{tx=e.touches[0].clientX;},{passive:true});lightbox.addEventListener('touchend',e=>{const dx=e.changedTouches[0].clientX-tx;if(Math.abs(dx)>50){dx<0?next():prev();}},{passive:true});function renderBatch(){const end=Math.min(rendered+BATCH,photos.length);const frag=document.createDocumentFragment();for(let i=rendered;i<end;i++){const div=document.createElement('div');div.className='trail-photo-item';div.dataset.index=i;const img=document.createElement('img');img.dataset.src=photos[i];img.src='data:image/svg+xml,<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 4 3"><rect fill="%23241e16" width="4" height="3"/></svg>';img.alt=cat.label;img.loading='lazy';img.className='blur-up';img.width=4;img.height=3;div.appendChild(img);div.addEventListener('click',()=>openLB(parseInt(div.dataset.index)));frag.appendChild(div);}grid.appendChild(frag);rendered=end;lazyLoad();loadMoreBtn.style.display=rendered>=photos.length?'none':'inline-flex';}const obs=new IntersectionObserver(entries=>{entries.forEach(e=>{if(e.isIntersecting){const img=e.target;if(img.dataset.src){const full=new Image();full.onload=()=>{img.src=img.dataset.src;delete img.dataset.src;img.classList.add('loaded');};full.src=img.dataset.src;obs.unobserve(img);}}});},{rootMargin:'400px'});function lazyLoad(){grid.querySelectorAll('img[data-src]').forEach(img=>obs.observe(img));}loadMoreBtn.addEventListener('click',renderBatch);renderBatch();})();
